CREATE OR REPLACE FUNCTION trigger_fct_tbiu_sc_atm_dep_detail() RETURNS trigger AS $BODY$
BEGIN

  if coalesce(NEW.seq_no::text, '') = '' or NEW.seq_no = 0 then
    select max(seq_no) into STRICT NEW.seq_no
    from sc_atm_dep_detail
    where (deposit_account_no = NEW.deposit_account_no);
    NEW.seq_no := coalesce(NEW.seq_no,0) + 1;
  end if;

  if coalesce(NEW.ref_sys_dep::text, '') = '' or NEW.ref_sys_dep = 0 then
    if NEW.item_type in ('WAT','RWA') then
      select max(seq_no) into STRICT NEW.ref_sys_dep
      from sc_dep_m_creditor_item
      where (deposit_account_no = NEW.deposit_account_no);
      NEW.ref_sys_dep := coalesce(NEW.ref_sys_dep,0);
    else
      NEW.ref_sys_dep := 0;
    end if;
  end if;

  if coalesce(NEW.prin_amount::text, '') = '' then NEW.prin_amount :=0;end if;
  if coalesce(NEW.fee_amount::text, '') = '' then NEW.fee_amount :=0;end if;
  if coalesce(NEW.dep_balance::text, '') = '' then NEW.dep_balance :=0;end if;
  if coalesce(NEW.approve_amount::text, '') = '' then NEW.approve_amount :=0;end if;

  if coalesce(OLD.DEPOSIT_ACCOUNT_NO::text, '') = '' and (NEW.DEPOSIT_ACCOUNT_NO IS NOT NULL AND NEW.DEPOSIT_ACCOUNT_NO::text <> '') then
    if pka.auto_entry then 
      NEW.entry_id := current_setting('app.login_id', true);
      NEW.entry_date := statement_timestamp();
      NEW.entry_br := current_setting('app.login_br', true);
      NEW.entry_pc := pka_com_login.login_pc;
    end if;
  end if;



RETURN NEW;
end
